noncompliant:
resource backup 'Microsoft.Web/sites/config@2022-03-01' = {
  name: 'webApp/backup'
  properties: {
    backupSchedule: {
      frequencyInterval: 1
      frequencyUnit: 'Day'
      keepAtLeastOneBackup: true
      retentionPeriodInDays: 2 // Sensitive: too short
    }
  }
}

compliant:
resource backup 'Microsoft.Web/sites/config@2022-03-01' = {
  name: 'webApp/backup'
  properties: {
    backupSchedule: {
      frequencyInterval: 1
      frequencyUnit: 'Day'
      keepAtLeastOneBackup: true
      retentionPeriodInDays: 30 // Meets compliance
    }
  }
}
